using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for edge/error cases ---

    [TestMethod]
    [DynamicData(nameof(InvalidQuantityData))]
    public void CalculateTotal_NegativeQuantity_Throws(decimal unitPrice, int quantity, decimal taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidQuantityData =>
    [
        (10m, -1, 0.1m),
        (5m, -100, 0.0m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidUnitPriceData))]
    public void CalculateTotal_NegativeUnitPrice_Throws(decimal unitPrice, int quantity, decimal taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidUnitPriceData =>
    [
        (-1m, 1, 0.1m),
        (-0.01m, 10, 0.0m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidTaxRateData))]
    public void CalculateTotal_InvalidTaxRate_Throws(decimal unitPrice, int quantity, decimal taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate)> InvalidTaxRateData =>
    [
        (10m, 1, -0.01m),
        (10m, 1, 1.01m),
        (10m, 1, 2.0m),
    ];

    // --- ApplyDiscount: DataRow for common scenarios ---

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off $100")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off $200")]
    [DataRow(50.00, 0.0, 50.00, DisplayName = "No discount")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% discount (free)")]
    [DataRow(33.33, 50.0, 16.665, DisplayName = "50% off odd price")]
    public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: DynamicData for invalid discount values ---

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountData))]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(decimal price, decimal discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));
    }

    public static IEnumerable<(decimal price, decimal discountPercent)> InvalidDiscountData =>
    [
        (100m, -1m),
        (100m, -0.01m),
        (100m, 100.01m),
        (100m, 200m),
    ];
}

